<?php namespace App\Domains\Apparel\Http\Controllers; use Illuminate\Http\Request; use App\Domains\Apparel\Models\Clothing; class ClothingController { public function index() { return response()->json(Clothing::all()); } public function store(Request $request) { $clothing = Clothing::create($request->all()); return response()->json($clothing, 201); } public function show(Clothing $clothing) { return response()->json($clothing); } public function update(Request $request, Clothing $clothing) { $clothing->update($request->all()); return response()->json($clothing); } public function destroy(Clothing $clothing) { $clothing->delete(); return response()->json(null, 204); } }
